import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as s,e as c}from"./app-be253e4c.js";const n={},t=c(`<h1 id="touch命令" tabindex="-1"><a class="header-anchor" href="#touch命令" aria-hidden="true">#</a> touch命令</h1><p><code>touch</code>命令用于修改文件或者目录的时间属性，包括存取时间和更改时间，若文件不存在，系统会建立一个新的文件。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">touch</span> <span class="token punctuation">[</span>OPTION<span class="token punctuation">]</span><span class="token punctuation">..</span>. FILE<span class="token punctuation">..</span>.
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-a</code>: 仅更改访问时间。</li><li><code>-c, --no-create</code>: 不创建任何文件。</li><li><code>-d, --date=STRING</code>: 解析<code>STRING</code>并使用其作为访问和修改时间。</li><li><code>-f</code>: 该参数被忽略。</li><li><code>-h, --no-dereference</code>: 影响每个符号链接，而不影响任何引用的文件，仅在可以更改符号链接时间戳的系统上有用。</li><li><code>-m</code>: 仅更改修改时间。</li><li><code>-r, --reference=FILE</code>: 使用此文件的时间而不是当前时间。</li><li><code>-t STAMP</code>: 使用<code>[[CC]YY]MMDDhhmm[.ss]</code>而不是当前时间。</li><li><code>--time=WORD</code>: 更改指定的时间，<code>WORD</code>是<code>access</code>、<code>atime</code>或<code>use</code>则等效于<code>-a</code>，<code>WORD</code>是<code>Modify</code>或<code>mtime</code>则等效于<code>-m</code>。</li><li><code>--help</code>: 显示帮助信息。</li><li><code>--version</code>: 显示版本信息。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>创建一个空白文件，如果文件已经存在，它将更改文件的访问时间。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">touch</span> /tmp/file.txt
</code></pre></div><p>创建多个文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">touch</span> /tmp/file1.txt /tmp/file2.txt /tmp/file3.txt
</code></pre></div><p>模板文件名创建文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>tmpwatch <span class="token parameter variable">-am</span> <span class="token number">30</span> –nodirs /tmp/
</code></pre></div><p>修改文件的访问时间并查看文件属性。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">touch</span> <span class="token parameter variable">-a</span> /tmp/file.txt <span class="token operator">&amp;&amp;</span> <span class="token function">stat</span> /tmp/file.txt
</code></pre></div><p>修改文件的修改时间并查看文件属性。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">touch</span> <span class="token parameter variable">-m</span> /tmp/file.txt <span class="token operator">&amp;&amp;</span> <span class="token function">stat</span> /tmp/file.txt
</code></pre></div><p>同时修改访问时间和修改时间并设置一个特定的访问与修改时间。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">touch</span> <span class="token parameter variable">-am</span> <span class="token parameter variable">-t</span> <span class="token number">202007010000.00</span> /tmp/file.txt <span class="token operator">&amp;&amp;</span> <span class="token function">stat</span> /tmp/file.txt
</code></pre></div>`,19),o=[t];function d(p,l){return e(),s("div",null,o)}const h=a(n,[["render",d],["__file","touch.html.vue"]]);export{h as default};
